import { NextRequest, NextResponse } from 'next/server'
import { retrieveCustomer } from '@/lib/data/customer'

const CUSTOMER_BACKEND_URL = process.env.NEXT_PUBLIC_CUSTOMER_BACKEND_URL || 'http://localhost:7000'

export async function GET(request: NextRequest) {
  try {
    // Get authenticated customer — unauthenticated users get empty array (not an error)
    const customer = await retrieveCustomer()

    if (!customer) {
      return NextResponse.json({ catalogSkus: [] })
    }

    // Fetch user's personal collections from customer-backend
    const collectionsResponse = await fetch(
      `${CUSTOMER_BACKEND_URL}/api/collections/user/${customer.id}?type=personal`,
      {
        method: 'GET',
        headers: { 'Content-Type': 'application/json' },
      }
    )

    if (!collectionsResponse.ok) {
      console.error(
        `[collection-sync] Failed to fetch collections for user ${customer.id}: ${collectionsResponse.status}`
      )
      return NextResponse.json({
        catalogSkus: [],
        error: 'Collection service unavailable',
      })
    }

    const collectionsData = await collectionsResponse.json()
    const collections = collectionsData?.data?.collections || []

    // Fetch cards for each personal collection and extract catalogSkus
    const catalogSkus: string[] = []

    for (const collection of collections) {
      try {
        const collectionResponse = await fetch(
          `${CUSTOMER_BACKEND_URL}/api/collections/${collection.id}`,
          {
            method: 'GET',
            headers: { 'Content-Type': 'application/json' },
          }
        )

        if (!collectionResponse.ok) {
          console.warn(
            `[collection-sync] Failed to fetch collection ${collection.id}: ${collectionResponse.status}`
          )
          continue
        }

        const collectionData = await collectionResponse.json()
        const cards = collectionData?.data?.collection?.cards || []

        for (const card of cards) {
          if (card.catalogSku) {
            catalogSkus.push(card.catalogSku)
          }
        }
      } catch (err) {
        console.warn(
          `[collection-sync] Error fetching collection ${collection.id}:`,
          err instanceof Error ? err.message : err
        )
      }
    }

    // Deduplicate
    const uniqueSkus = [...new Set(catalogSkus)]

    return NextResponse.json({ catalogSkus: uniqueSkus })
  } catch (error) {
    console.error(
      '[collection-sync] Unexpected error:',
      error instanceof Error ? error.message : error
    )
    return NextResponse.json({
      catalogSkus: [],
      error: 'Collection service unavailable',
    })
  }
}

