const syncServerOwnedCards = useCallback(async (deckId: string) => {
  if (!isAuthenticated) return
  try {
    const response = await fetch('/api/collection/owned', {
      method: 'GET',
      credentials: 'include',
    })
    if (!response.ok) return
    const data = await response.json()
    const serverSkus: string[] = data?.catalogSkus || []
    if (serverSkus.length === 0) return
    let added = false
    for (const sku of serverSkus) {
      if (!ownedCardsRef.current.has(sku)) {
        ownedCardsRef.current.add(sku)
        added = true
      }
    }
    if (added) {
      setOwnedCardsVersion(v => v + 1)
      saveOwnedCards(deckId)
    }
  } catch {
    // Sync failure is non-fatal — local state preserved
  }
}, [isAuthenticated, saveOwnedCards])

