import { describe, it, expect, vi, beforeEach } from 'vitest'

// Mock retrieveCustomer before importing the route
vi.mock('@/lib/data/customer', () => ({
  retrieveCustomer: vi.fn(),
}))

import { GET } from '../owned/route'
import { retrieveCustomer } from '@/lib/data/customer'

const mockRetrieveCustomer = retrieveCustomer as ReturnType<typeof vi.fn>

function makeRequest() {
  return new Request('http://localhost/api/collection/owned') as unknown as import('next/server').NextRequest
}

describe('GET /api/collection/owned', () => {
  beforeEach(() => {
    vi.restoreAllMocks()
  })

  it('returns catalogSkus from personal collections', async () => {
    mockRetrieveCustomer.mockResolvedValue({ id: 'cust-1' })

    const collectionsPayload = {
      success: true,
      data: {
        collections: [
          { id: 'col-1', type: 'personal', cardCount: 2 },
        ],
        total: 1,
      },
    }

    const collectionDetailPayload = {
      success: true,
      data: {
        collection: {
          id: 'col-1',
          cards: [
            { catalogSku: 'MTG-SET1-001', quantity: 1, condition: 'NM' },
            { catalogSku: 'MTG-SET1-002', quantity: 2, condition: 'LP' },
          ],
        },
      },
    }

    vi.stubGlobal(
      'fetch',
      vi.fn()
        .mockResolvedValueOnce({
          ok: true,
          json: async () => collectionsPayload,
        })
        .mockResolvedValueOnce({
          ok: true,
          json: async () => collectionDetailPayload,
        })
    )

    const response = await GET(makeRequest())
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(body.catalogSkus).toEqual(
      expect.arrayContaining(['MTG-SET1-001', 'MTG-SET1-002'])
    )
    expect(body.catalogSkus).toHaveLength(2)
    expect(body.error).toBeUndefined()
  })

  it('returns empty array when user has no collections', async () => {
    mockRetrieveCustomer.mockResolvedValue({ id: 'cust-2' })

    vi.stubGlobal(
      'fetch',
      vi.fn().mockResolvedValue({
        ok: true,
        json: async () => ({
          success: true,
          data: { collections: [], total: 0 },
        }),
      })
    )

    const response = await GET(makeRequest())
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(body.catalogSkus).toEqual([])
    expect(body.error).toBeUndefined()
  })

  it('returns empty array when unauthenticated', async () => {
    mockRetrieveCustomer.mockResolvedValue(null)

    const response = await GET(makeRequest())
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(body.catalogSkus).toEqual([])
    expect(body.error).toBeUndefined()
  })

  it('returns empty array with error message when customer-backend is unreachable', async () => {
    mockRetrieveCustomer.mockResolvedValue({ id: 'cust-3' })

    vi.stubGlobal(
      'fetch',
      vi.fn().mockRejectedValue(new Error('ECONNREFUSED'))
    )

    const response = await GET(makeRequest())
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(body.catalogSkus).toEqual([])
    expect(body.error).toBe('Collection service unavailable')
  })

  it('filters to personal collections only (ignores wishlist/trading/showcase)', async () => {
    mockRetrieveCustomer.mockResolvedValue({ id: 'cust-4' })

    // The BFF sends ?type=personal to customer-backend, so only personal collections
    // should be returned. We verify the fetch URL includes the type filter.
    const mockFetch = vi.fn().mockResolvedValue({
      ok: true,
      json: async () => ({
        success: true,
        data: { collections: [], total: 0 },
      }),
    })
    vi.stubGlobal('fetch', mockFetch)

    await GET(makeRequest())

    // First fetch call should be to /api/collections/user/{id}?type=personal
    expect(mockFetch).toHaveBeenCalledTimes(1)
    const calledUrl = mockFetch.mock.calls[0][0] as string
    expect(calledUrl).toContain('/api/collections/user/cust-4')
    expect(calledUrl).toContain('type=personal')
  })

  it('deduplicates catalogSkus across multiple collections', async () => {
    mockRetrieveCustomer.mockResolvedValue({ id: 'cust-5' })

    const collectionsPayload = {
      success: true,
      data: {
        collections: [
          { id: 'col-A', type: 'personal', cardCount: 1 },
          { id: 'col-B', type: 'personal', cardCount: 1 },
        ],
        total: 2,
      },
    }

    const mockFetch = vi.fn()
      .mockResolvedValueOnce({
        ok: true,
        json: async () => collectionsPayload,
      })
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          success: true,
          data: {
            collection: {
              id: 'col-A',
              cards: [{ catalogSku: 'SHARED-001', quantity: 1, condition: 'NM' }],
            },
          },
        }),
      })
      .mockResolvedValueOnce({
        ok: true,
        json: async () => ({
          success: true,
          data: {
            collection: {
              id: 'col-B',
              cards: [{ catalogSku: 'SHARED-001', quantity: 2, condition: 'LP' }],
            },
          },
        }),
      })
    vi.stubGlobal('fetch', mockFetch)

    const response = await GET(makeRequest())
    const body = await response.json()

    expect(body.catalogSkus).toEqual(['SHARED-001'])
  })

  it('returns empty array when customer-backend returns non-ok status', async () => {
    mockRetrieveCustomer.mockResolvedValue({ id: 'cust-6' })

    vi.stubGlobal(
      'fetch',
      vi.fn().mockResolvedValue({
        ok: false,
        status: 500,
      })
    )

    const response = await GET(makeRequest())
    const body = await response.json()

    expect(response.status).toBe(200)
    expect(body.catalogSkus).toEqual([])
    expect(body.error).toBe('Collection service unavailable')
  })
})

import { describe, it, expect, vi, beforeEach, afterEach } from 'vitest'
import { render, act, waitFor } from '@testing-library/react'
import React from 'react'
import { DeckBuilderProvider, useDeckBuilder } from '../DeckBuilderContext'
import type { Deck } from '@/types/deck'

// ─── Mocks ────────────────────────────────────────────────────────────────────

vi.mock('@/hooks/useFeedback', () => ({
  useFeedback: () => ({
    executeWithFeedback: async (fn: () => Promise<void>) => fn(),
  }),
}))

vi.mock('@/hooks/useCustomer', () => ({
  useCustomer: () => ({
    customer: { id: 'cust-1' },
    isAuthenticated: true,
  }),
}))

vi.mock('@/lib/validation/deck-validation', () => ({
  validateDeck: () => ({ isValid: true, errors: [], warnings: [] }),
  useRealtimeDeckValidation: () => ({ isValid: true, errors: [], warnings: [] }),
  GAME_FORMATS: {},
}))

vi.mock('@/lib/data/cards', () => ({
  getGames: () => Promise.resolve([]),
}))

vi.mock('@/lib/api/customer-backend', () => ({
  customerBackendAPI: {},
}))

// ─── Helpers ──────────────────────────────────────────────────────────────────

function makeDeck(overrides: Partial<Deck> = {}): Deck {
  return {
    id: 'deck-sync-1',
    name: 'Sync Test Deck',
    game: 'MTG',
    format: 'Standard',
    isPublic: false,
    isValid: true,
    createdAt: new Date(),
    updatedAt: new Date(),
    cards: {
      main: [
        {
          catalogSku: 'MTG-SET1-001',
          card: { id: 'c1', name: 'Lightning Bolt', game: 'MTG' },
          quantity: 4,
          zone: 'main',
        },
      ],
      sideboard: [],
    },
    ...overrides,
  }
}

function TestHarness({
  onContextReady,
}: {
  onContextReady?: (ctx: ReturnType<typeof useDeckBuilder>) => void
}) {
  const ctx = useDeckBuilder()

  React.useEffect(() => {
    onContextReady?.(ctx)
  })

  return (
    <div>
      <span data-testid="owned-check">
        {ctx.isOwned('MTG-SET1-001') ? 'owned' : 'not-owned'}
      </span>
    </div>
  )
}

function renderWithProvider() {
  let ctxRef: ReturnType<typeof useDeckBuilder> | undefined

  const utils = render(
    <DeckBuilderProvider>
      <TestHarness
        onContextReady={(ctx) => {
          ctxRef = ctx
        }}
      />
    </DeckBuilderProvider>
  )

  return {
    ...utils,
    getCtx: () => ctxRef!,
  }
}

// ─── localStorage mock ────────────────────────────────────────────────────────

let localStorageStore: Record<string, string> = {}

beforeEach(() => {
  localStorageStore = {}
  vi.spyOn(Storage.prototype, 'getItem').mockImplementation(
    (key: string) => localStorageStore[key] ?? null
  )
  vi.spyOn(Storage.prototype, 'setItem').mockImplementation(
    (key: string, value: string) => {
      localStorageStore[key] = value
    }
  )
  vi.spyOn(Storage.prototype, 'removeItem').mockImplementation(
    (key: string) => {
      delete localStorageStore[key]
    }
  )
})

afterEach(() => {
  vi.restoreAllMocks()
})

// ─── Tests ────────────────────────────────────────────────────────────────────

describe('DeckBuilderContext — Collection Sync', () => {
  it('server-owned SKUs are merged into ownedCardsRef on deck load', async () => {
    const deck = makeDeck()
    const deckResponse = { data: deck }

    // Mock fetch: loadDeck API, then format fetch, then collection sync
    vi.spyOn(globalThis, 'fetch').mockImplementation(async (url) => {
      const urlStr = typeof url === 'string' ? url : (url as URL).toString()

      if (urlStr.includes('/api/decks/')) {
        return {
          ok: true,
          json: async () => deckResponse,
        } as Response
      }
      if (urlStr.includes('/api/formats/')) {
        return {
          ok: false,
          status: 404,
        } as Response
      }
      if (urlStr.includes('/api/collection/owned')) {
        return {
          ok: true,
          json: async () => ({
            catalogSkus: ['SERVER-SKU-001', 'SERVER-SKU-002'],
          }),
        } as Response
      }
      return { ok: false, status: 404 } as Response
    })

    const { getCtx } = renderWithProvider()
    const ctx = getCtx()

    // Load deck — triggers loadOwnedCards then syncServerOwnedCards
    await act(async () => {
      await ctx.loadDeck('deck-sync-1')
    })

    // Wait for the async sync to complete
    await waitFor(() => {
      expect(getCtx().isOwned('SERVER-SKU-001')).toBe(true)
    })
    expect(getCtx().isOwned('SERVER-SKU-002')).toBe(true)
  })

  it('manually toggled local SKUs are preserved after server sync (additive)', async () => {
    const deck = makeDeck()
    const deckResponse = { data: deck }

    // Pre-populate localStorage with a locally toggled SKU
    localStorageStore['sd-owned-deck-sync-1'] = JSON.stringify(['LOCAL-SKU-999'])

    vi.spyOn(globalThis, 'fetch').mockImplementation(async (url) => {
      const urlStr = typeof url === 'string' ? url : (url as URL).toString()

      if (urlStr.includes('/api/decks/')) {
        return {
          ok: true,
          json: async () => deckResponse,
        } as Response
      }
      if (urlStr.includes('/api/formats/')) {
        return { ok: false, status: 404 } as Response
      }
      if (urlStr.includes('/api/collection/owned')) {
        return {
          ok: true,
          json: async () => ({
            catalogSkus: ['SERVER-SKU-001'],
          }),
        } as Response
      }
      return { ok: false, status: 404 } as Response
    })

    const { getCtx } = renderWithProvider()

    await act(async () => {
      await getCtx().loadDeck('deck-sync-1')
    })

    await waitFor(() => {
      expect(getCtx().isOwned('SERVER-SKU-001')).toBe(true)
    })

    // Local SKU should still be owned — additive, never removed
    expect(getCtx().isOwned('LOCAL-SKU-999')).toBe(true)
  })

  it('sync failure (fetch error) does not crash — local state preserved', async () => {
    const deck = makeDeck()
    const deckResponse = { data: deck }

    // Pre-populate localStorage
    localStorageStore['sd-owned-deck-sync-1'] = JSON.stringify(['LOCAL-SKU-AAA'])

    vi.spyOn(globalThis, 'fetch').mockImplementation(async (url) => {
      const urlStr = typeof url === 'string' ? url : (url as URL).toString()

      if (urlStr.includes('/api/decks/')) {
        return {
          ok: true,
          json: async () => deckResponse,
        } as Response
      }
      if (urlStr.includes('/api/formats/')) {
        return { ok: false, status: 404 } as Response
      }
      if (urlStr.includes('/api/collection/owned')) {
        throw new Error('Network failure')
      }
      return { ok: false, status: 404 } as Response
    })

    const { getCtx } = renderWithProvider()

    // Should not throw
    await act(async () => {
      await getCtx().loadDeck('deck-sync-1')
    })

    // Allow sync promise to settle
    await act(async () => {
      await new Promise(r => setTimeout(r, 50))
    })

    // Local state should still be intact
    expect(getCtx().isOwned('LOCAL-SKU-AAA')).toBe(true)
  })

  it('duplicate SKUs between server and local do not cause issues', async () => {
    const deck = makeDeck()
    const deckResponse = { data: deck }

    // Both local and server have the same SKU
    localStorageStore['sd-owned-deck-sync-1'] = JSON.stringify(['SHARED-SKU-001'])

    vi.spyOn(globalThis, 'fetch').mockImplementation(async (url) => {
      const urlStr = typeof url === 'string' ? url : (url as URL).toString()

      if (urlStr.includes('/api/decks/')) {
        return {
          ok: true,
          json: async () => deckResponse,
        } as Response
      }
      if (urlStr.includes('/api/formats/')) {
        return { ok: false, status: 404 } as Response
      }
      if (urlStr.includes('/api/collection/owned')) {
        return {
          ok: true,
          json: async () => ({
            catalogSkus: ['SHARED-SKU-001', 'NEW-SKU-002'],
          }),
        } as Response
      }
      return { ok: false, status: 404 } as Response
    })

    const { getCtx } = renderWithProvider()

    await act(async () => {
      await getCtx().loadDeck('deck-sync-1')
    })

    await waitFor(() => {
      expect(getCtx().isOwned('NEW-SKU-002')).toBe(true)
    })

    // Shared SKU is still owned (not duplicated or removed)
    expect(getCtx().isOwned('SHARED-SKU-001')).toBe(true)

    // Verify localStorage was saved with both SKUs (no duplicates)
    const stored = JSON.parse(localStorageStore['sd-owned-deck-sync-1'] || '[]')
    const uniqueStored = [...new Set(stored)]
    expect(stored.length).toBe(uniqueStored.length)
  })
})

